function getValidClasses(classNum) {
    if (classNum % 2 === 0) {
        return [classNum - 1, classNum];
    } else {
        return [classNum, classNum + 1];
    }
}

/**
 * 학적정보에 따라 시간표를 반환하는 함수
 * @param {string} gradeNum - N
 * @param {string} classNum - N
 * @param {string} numberNum - N
 * @param {string} schoolNum - NNNN
 * @param {string} numberNum - N
 */
async function getTimetable(gradeNum, classNum, numberNum, schoolNum, trace) {
    try {
        [gradeNum, classNum, numberNum] = [gradeNum, classNum, numberNum].map(Number);
        if (isNaN(gradeNum) || isNaN(classNum) || isNaN(numberNum)) {
            return {
                success: false,
                data: null,
                message: notice.client.USER_NOT_FOUND,
                error: null
            }
        }

        if (gradeNum === 1) {
            let arr = [];
            for (let i = 0; i < timetableData_1.length; i++) {
                /**
                 * 2학년 음악/미술 보정코드 (2025학년 1학기 기준)
                 */
                if (timetableData_1[i].classQuery.includes('음악')) {
                    continue;
                }
                if (timetableData_1[i].classQuery.includes('미술')) {
                    const classOfClass = timetableData_1[i]['class'];
                    if (getValidClasses(classNum).includes(classOfClass)) {
                        timetableData_1[i].subject = '음/미';
                        timetableData_1[i].classQuery = '음/미';
                        timetableData_1[i].teacher = '최수미</br>홍현숙';
                        arr.push(timetableData_1[i]);
                        continue;
                    }
                }
                if (timetableData_1[i].class === classNum) {
                    arr.push(timetableData_1[i]);
                }
            }
            return {
                success: true,
                data: arr,
                message: notice.client.SUCCESS,
                error: null
            };
        } else if (gradeNum === 2 || gradeNum === 3) {
            let result = [];
            const personalSelectSubject = await getPersonalSelectSubject(convertToSchoolNum(gradeNum, classNum, numberNum), trace);
            if (!personalSelectSubject.success) {
                return {
                    success: false,
                    data: null,
                    message: personalSelectSubject.message,
                    error: null
                };
            }

            const convert_personal_select_subject = await convertPersonalSelectSubject(schoolNum, personalSelectSubject.data, trace);
            if (!convert_personal_select_subject.success) {
                return {
                    success: false,
                    data: null,
                    message: convert_personal_select_subject.message,
                    error: null
                };
            }

            const psData = convert_personal_select_subject.data;
            const csData = gradeNum === 2 ? timetableData_2 : timetableData_3;  

            for (const psItem of psData) {
                /**
                 * 기본 코드
                 */
                for (let i = 0; i < csData.length; i++) {
                    const gradeOfClass = csData[i]['grade'];
                    const classOfClass = csData[i]['class'];
                    const classQuery = csData[i]['classQuery'].replace(/1/g, '');
                    
                    const psItems = psItem.replace(/1/g, '');
                    if (classQuery.includes(psItems)){
                        result.push(csData[i]);
                    }
                }
            }

            /**
             * 2학년 공강 독서 보정코드 (2026학년 기준)
             * 공강 시간에 독서 과목을 자동 삽입
             * symbol: A=월, B=화, C=수, D=목, E=금 + 교시번호
             */
            if (gradeNum === 2) {
                const readingSlots = ['A5', 'A6', 'B1', 'C1', 'C6', 'D1', 'D2'];

                for (const symbol of readingSlots) {
                    const exists = result.some(item => item.symbol === symbol);
                    if (!exists) {
                        result.push({
                            grade: gradeNum,
                            class: classNum,
                            date: '20240304',
                            period: Number(symbol[1]),
                            subject: '독서',
                            classQuery: '독서',
                            teacher: '',
                            symbol: symbol,
                        });
                    }
                }
            }
            if (gradeNum === 2 || gradeNum === 3) {
                const readingSlots = ['A7'];

                for (const symbol of readingSlots) {
                    const exists = result.some(item => item.symbol === symbol);
                    if (!exists) {
                        result.push({
                            grade: gradeNum,
                            class: classNum,
                            date: '20240304',
                            period: Number(symbol[1]),
                            subject: '창체',
                            classQuery: '창체',
                            teacher: '동아리',
                            symbol: symbol,
                        });
                    }
                }
            }

            if (gradeNum === 1 ||gradeNum === 2 || gradeNum === 3) {
                const readingSlots = ['E6', 'E7'];

                for (const symbol of readingSlots) {
                    const exists = result.some(item => item.symbol === symbol);
                    if (!exists) {
                        result.push({
                            grade: gradeNum,
                            class: classNum,
                            date: '20240304',
                            period: Number(symbol[1]),
                            subject: '창체',
                            classQuery: '창체',
                            teacher: '',
                            symbol: symbol,
                        });
                    }
                }
            }

            return {
                success: true,
                data: result,
                message: notice.client.SUCCESS,
                error: null
            };
        }
    } catch (e) {
        await db.recordErrorLog(notice.TIMETABLE.GET_100.CODE, e.message, e.stack, trace);
        return {
            success: false,
            data: null,
            message: notice.client.SERVER_ERROR,
            error: null
        };
    }
}

/**
 * 개인별 선택과목을 매칭하기 전, 데이터를 가공하는 함수
 * @param {string} schoolNum
 * @param {object} data 
 * @param {object} trace 
 * @returns 
 */
async function convertPersonalSelectSubject(schoolNum, data, trace) {
    try {
        const result = [];
        const keys = Object.keys(data);
        for (const key of keys) {
            if (key === 'schoolNum' || key === 'name' || data[key] === '') continue;
            const grade = extractGrade(schoolNum);
            const subjectName = ( grade == 2 ? subjectList_grade2[key] : subjectList_grade3[key] ) + data[key].toUpperCase();



            result.push(subjectName);
        }

        return {
            success: true,
            data: result,
            message: notice.client.SUCCESS,
            error: null
        };
    } catch (e) {
        await db.recordErrorLog(notice.TIMETABLE.CONVERT_100.CODE, e.message, e.stack, trace);
        return {
            success: false,
            data: null,
            message: notice.client.SERVER_ERROR,
            error: null
        };   
    }
}

/**
 * 개인별 선택과목 불러오는 함수
 * @param {string} schoolNum 
 * @param {object} trace 
 * @returns 
 */
async function getPersonalSelectSubject(schoolNum, trace) {
    try {
        const query = await db.querySQL(`SELECT * FROM personalSelectSubject_${extractGrade(schoolNum)} WHERE schoolNum = ?`, [schoolNum], trace);
        if (!query) {
            return {
                success: false,
                data: null,
                message: notice.client.QUERY_ERROR,
                error: null
            };
        }

        return {
            success: true,
            data: query[0],
            message: notice.client.SUCCESS,
            error: null
        };
    } catch (e) {
        await db.recordErrorLog(notice.TIMETABLE.GET_101.CODE, e.message, e.stack, trace);
        return {
            success: false,
            data: null,
            message: notice.client.SERVER_ERROR,
            error: null
        };
    } 
}

/**
 * 학적정보를 기반으로 학번으로 바꿔주는 함수
 * @param {number} gradeNum 
 * @param {number} classNum 
 * @param {number} numberNum 
 * @returns 
 */
function convertToSchoolNum(gradeNum, classNum, numberNum) {
    const formattedNumber = Number(numberNum) < 10 ? `0${numberNum}` : `${numberNum}`;
    return `${String(gradeNum)}${String(classNum)}${formattedNumber}`;
}


/**
 * 학번에서 학년만 추출하는 함수
 * @param {string} schoolNum 
 */
function extractGrade(schoolNum) {
    const firstDigit = String(schoolNum)[0];
    return Number(firstDigit) > 0 ? Number(firstDigit) : null;
}

module.exports = {
    getTimetable, convertToSchoolNum
}
